// Acessa o corpo recebido
const body = items[0].json.body || {};
let msg = body.message || {};
const chat = body.chat || {};

// ====================================================================
// 1. EXTRAÇÃO DO TELEFONE E OWNER
// ====================================================================

const owner = 
    body.owner ||           
    (msg && !Array.isArray(msg) ? msg.owner : '') ||            
    chat.owner ||           
    body.instanceName ||    
    '';

let rawChatId = 
    (msg && !Array.isArray(msg) ? msg.chatid : '') ||           
    chat.wa_chatid ||       
    (msg && !Array.isArray(msg) ? msg.key?.remoteJid : '') ||   
    (msg && !Array.isArray(msg) ? msg.remoteJid : '') ||        
    chat.phone ||           
    (msg && !Array.isArray(msg) ? msg.sender_pn : '') ||        
    ''; 

let rawPhone = rawChatId;
const phone = rawPhone ? rawPhone.replace(/\D/g, '').split('@')[0] : null;

// ====================================================================
// 2. EXTRAÇÃO DA MENSAGEM
// ====================================================================
let content = '';

// Suporte ao novo formato de media (Array com fileURL)
if (Array.isArray(msg) && msg.length > 0 && msg[0].fileURL) {
    content = msg[0].fileURL;
} else if (msg.files && Array.isArray(msg.files) && msg.files.length > 0 && msg.files[0].fileURL) {
    content = msg.files[0].fileURL;
} else if (msg.fileURL) {
    content = msg.fileURL;
}

// 1. Tenta pegar texto/legenda (se não for o novo formato de media)
if (!content) {
    content = 
      msg.text || 
      msg.conversation || 
      msg.extendedTextMessage?.text || 
      msg.imageMessage?.caption || 
      msg.videoMessage?.caption || 
      msg.documentMessage?.caption ||
      msg.content?.text ||
      msg.content?.caption ||
      '';
}

// 2. Se não houver texto, verifica se é mídia
if (!content || content.trim() === '') {
    const type = msg.type || msg.messageType || '';
    const isImage = type.toLowerCase().includes('image') || type === 'media';
    const isAudio = type.toLowerCase().includes('audio') || type === 'ptt' || type === 'voice';

    if (isImage) {
        content = '[Imagem]';
    } else if (isAudio) {
        content = '[Áudio]';
    } else if (type !== '' && type !== 'text') {
        content = `[Arquivo: ${type}]`;
    }
}

// ====================================================================
// 3. RETORNO
// ====================================================================
const isFromMe = msg.fromMe === true;
const direction = isFromMe ? 'outbound' : 'inbound';
const status = isFromMe ? 'sent' : 'received';
const messageId = msg.id || msg.messageid || (msg.key ? msg.key.id : '') || '';

// Só salva se tiver telefone E alguma mensagem/mídia
const isValid = (phone && phone.length > 8 && content && content.trim() !== '') ? true : false;

return [{
    json: {
      phone: phone,
      owner: owner,
      message: content,
      direction: direction,
      status: status,
      isValid: isValid,
      message_id: messageId
    }
}];

const results = [];

for (const item of items) {
    // --- CORREÇÃO DO BLOQUEIO ---
    // O Postgres pode retornar: true (bool), "true" (string) ou "t" (string)
    const rawPaused = item.json.ai_paused;
    const isPaused = rawPaused === true || rawPaused === 'true' || rawPaused === 't';

    // Se o banco não retornou nada, assume 999 (muito tempo)
    let minutosPassados = 999;

    if (item.json.minutos_passados !== undefined && item.json.minutos_passados !== null) {
        minutosPassados = parseFloat(item.json.minutos_passados);
    }

    let blocked = false;
    let unpause = false;

    // CONFIGURAÇÃO: 3 minutos de silêncio após você falar
    const TEMPO_LIMITE = 3; 

    // REGRA 1: Se faz MENOS de 3 minutos que você falou, BLOQUEIA.
    if (minutosPassados <= TEMPO_LIMITE) {
        blocked = true;
        unpause = false; 
    } 
    // REGRA 2: Se já passou o tempo, mas a IA ainda está pausada no banco, libera.
    else if (isPaused) {
        blocked = false; 
        unpause = true; 
    }

    results.push({
        json: {
            ...item.json,
            blocked: blocked,
            unpause_needed: unpause,
            debug_paused_lido: isPaused // Para confirmar que agora leu certo
        }
    });
}

return results;

let textoFinal = "";

// 1. Veio do fluxo de TEXTO? (Verifica se Concatenar rodou)
if ($("Concatenar mensagens").isExecuted) {
    const dados = $("Concatenar mensagens").first().json;
    textoFinal = dados.mensagem;
} 
// 2. Veio do fluxo de ÁUDIO ou IMAGEM? (Verifica inputs diretos)
else {
    const info = $("Info").first().json;
    const caption = info.mensagem || "";

    // Se for imagem (veio do Edit Fields)
    if ($("Edit Fields").isExecuted) {
        const description = $json.mensagem || $json.text || "";
        textoFinal = `[Legenda do Usuário]: ${caption}\n\n[Descrição da Imagem]: ${description}`;
    } else {
        textoFinal = $json.mensagem || $json.text || $json.caption || caption;
    }
}

// Fallback de segurança
if (!textoFinal || textoFinal.trim() === "") {
    textoFinal = "Mensagem do usuário vazia ou anexo sem legenda.";
}

// Entrega para a IA com a chave correta 'input'
return [
  {
    json: {
      input: textoFinal
    }
  }
];

const items = $input.all();
if (items.length === 0) {
    return [{ json: { historico_recente: "Nenhum histórico encontrado." } }];
}

// Supabase retorna DESC (mais recentes primeiro)
const rawMessages = items.map(i => i.json);

// SCAN TOTAL (nas 50 mensagens) para detectar se a venda já foi concluída
const fulfillmentFound = rawMessages.some(m => {
    const msg = String(m.message || '').toLowerCase();
    const isOutbound = ['outbound', 'sent', 'out'].includes(String(m.direction || '').toLowerCase());
    return isOutbound && (
        msg.includes('usuário') || 
        msg.includes('senha') || 
        msg.includes('login') || 
        msg.includes('acesso ao office') ||
        /\b[A-Z0-9]{5}-[A-Z0-9]{5}-[A-Z0-9]{5}-[A-Z0-9]{5}-[A-Z0-9]{5}\b/.test(m.message)
    );
});

const statusTag = fulfillmentFound ? 
    "\n[SISTEMA: VENDA JÁ CONCLUÍDA - PRODUTO ENTREGUE ANTERIORMENTE. FOQUE APENAS NO SUPORTE E IGNORE PAGAMENTOS.]\n" : "";

// Pegar as últimas 20 mensagens, reverter para ordem cronológica (ASC)
const finalHistory = rawMessages
    .slice(0, 20)
    .reverse() 
    .map(m => {
        const direction = String(m.direction || '').toLowerCase();
        const isOutbound = ['outbound', 'sent', 'out'].includes(direction);
        const timestamp = new Date(m.created_at).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Sao_Paulo' });
        // Identifica se a mensagem partiu da IA ou de um Humano
        const isAI = isOutbound && (m.sender_phone === 'Agente SuperSoftware' || m.sender_phone === 'superbot' || m.sender_phone === 'H5Ti5RcPjjoWFUZS');
        const prefix = isOutbound ? (isAI ? 'Emerson (IA): ' : 'Suporte Humano: ') : 'Cliente: ';
        return `[${timestamp}] ${prefix}${m.message}`;
    })
    .join('\n');

return [{ json: { historico_recente: statusTag + finalHistory || "Sem histórico relevante." } }];

const ultima_mensagem_da_fila = $input.last()
const mensagem_do_workflow = $('Info').first()

if (ultima_mensagem_da_fila.json.id_mensagem !== mensagem_do_workflow.json.id_mensagem) {
  // Mensagem encavalada, para o workflow
  return [];
}

// Pass-through da fila de mensagens
return $input.all();

